namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Toast bread slices", "Dice tomatoes with garlic and basil", "Top bread with tomato mixture"],
            AverageRating = 4.2, RatingCount = 5
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parsley", "Breadcrumbs"],
            Steps = ["Remove mushroom stems", "Mix filling ingredients", "Fill caps and bake at 375°F for 20 min"],
            AverageRating = 4.5, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan", "Black pepper"],
            Steps = ["Cook pasta al dente", "Fry pancetta until crispy", "Mix eggs and cheese", "Toss hot pasta with egg mixture and pancetta"],
            AverageRating = 4.8, RatingCount = 12
        },
        new()
        {
            Id = 4, Title = "Chicken Stir-Fry", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
            Steps = ["Slice chicken and vegetables", "Stir-fry chicken until cooked", "Add vegetables and sauce", "Serve over rice"],
            AverageRating = 4.0, RatingCount = 6
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter", "Whisk eggs and sugar", "Fold in flour and chocolate", "Bake at 425°F for 12 min"],
            AverageRating = 4.9, RatingCount = 15
        },
        new()
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs"],
            Steps = ["Dip ladyfingers in espresso", "Layer with mascarpone cream", "Refrigerate overnight", "Dust with cocoa"],
            AverageRating = 4.7, RatingCount = 10
        }
    ];

    private readonly Dictionary<int, List<int>> _ratings = new();

    public List<Recipe> GetByCategory(string categorySlug)
        => _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetById(int id)
        => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];

        _ratings[recipeId].Add(stars);

        var recipe = GetById(recipeId);
        if (recipe is not null)
        {
            recipe.RatingCount = _ratings[recipeId].Count + recipe.RatingCount;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }
}

