<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps)
        {
            <li>@step</li>
        }
    </ol>

    <hr />
    <StarRating RecipeId="Recipe.Id" CurrentRating="Recipe.AverageRating" RatingCount="Recipe.RatingCount" />
}

<a href="recipes/@Recipe?.CategorySlug" class="btn btn-secondary mt-3">← Back to Category</a>

@code {
    [Parameter] public int Id { get; set; }

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="my-3">
    <h4>Rate this Recipe</h4>
    <div class="d-flex align-items-center gap-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button class="btn btn-link p-0 fs-3 text-decoration-none"
                    @onclick="() => SubmitRating(star)"
                    title="Rate @star stars">
                @(star <= SelectedRating ? "★" : "☆")
            </button>
        }
        <span class="ms-2 text-muted">
            @CurrentRating.ToString("F1") avg (@RatingCount ratings)
        </span>
    </div>
    @if (RatingSubmitted)
    {
        <div class="alert alert-success mt-2" role="alert">
            Thanks! You rated this recipe @SelectedRating star(s).
        </div>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int SelectedRating { get; set; }
    private bool RatingSubmitted { get; set; }

    private void SubmitRating(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }

        RatingSubmitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer

@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@NewRecipe.Title</strong>" has been added. 
           <a href="recipe/@NewRecipe.Id">View it here</a>.</p>
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="NewRecipe" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Title</label>
            <InputText class="form-control" @bind-Value="NewRecipe.Title" />
        </div>

        <div class="mb-3">
            <label class="form-label">Category</label>
            <InputSelect class="form-select" @bind-Value="NewRecipe.CategorySlug">
                <option value="">-- Select --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label class="form-label">Ingredients (one per line)</label>
            <InputTextArea class="form-control" rows="5" @bind-Value="IngredientsText" />
        </div>

        <div class="mb-3">
            <label class="form-label">Steps (one per line)</label>
            <InputTextArea class="form-control" rows="5" @bind-Value="StepsText" />
        </div>

        <button type="submit" class="btn btn-success"
                disabled="@(string.IsNullOrWhiteSpace(NewRecipe.Title) || string.IsNullOrWhiteSpace(NewRecipe.CategorySlug))">
            Submit Recipe
        </button>
    </EditForm>
}

@code {
    private Recipe NewRecipe { get; set; } = new();
    private string IngredientsText { get; set; } = string.Empty;
    private string StepsText { get; set; } = string.Empty;
    private bool Submitted { get; set; }

    private void HandleSubmit()
    {
        NewRecipe.Ingredients = IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        NewRecipe.Steps = StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        NewRecipe.Category = NewRecipe.CategorySlug.Replace("-", " ");

        RecipeService.AddRecipe(NewRecipe);
        Submitted = true;
    }

    private void Reset()
    {
        NewRecipe = new();
        IngredientsText = string.Empty;
        StepsText = string.Empty;
        Submitted = false;
    }
}

